class RangeModule:

    def __init__(self):
        self.ranges = []

    def addRange(self, left: int, right: int) -> None:
        if not self.ranges:
            self.ranges.append([left, right])
            return

        i = 0
        while i < len(self.ranges):
            if right <= self.ranges[i][0]:
                self.ranges.insert(i, [left, right])
                return
            elif left >= self.ranges[i][1]:
                i += 1
            else:
                if left <= self.ranges[i][0]:
                    self.ranges[i][0] = left
                if right >= self.ranges[i][1]:
                    self.ranges[i][1] = right
                else:
                    self.ranges.insert(i + 1, [right, self.ranges[i][1]])
                    self.ranges[i][1] = left
                    i += 1
                break
        else:
            self.ranges.append([left, right])

    def queryRange(self, left: int, right: int) -> bool:
        i = 0
        while i < len(self.ranges):
            if self.ranges[i][1] <= left:
                i += 1
            elif self.ranges[i][0] >= right:
                return False
            else:
                if self.ranges[i][0] <= left and self.ranges[i][1] >= right:
                    return True
                elif self.ranges[i][0] <= left:
                    left = self.ranges[i][1]
                    i += 1
                else:
                    return False

    def removeRange(self, left: int, right: int) -> None:
        i = 0
        while i < len(self.ranges):
            if self.ranges[i][1] <= left:
                i += 1
            elif self.ranges[i][0] >= right:
                break
            else:
                if self.ranges[i][0] < left:
                    self.ranges.insert(i, [self.ranges[i][0], left])
                    i += 1
                if self.ranges[i][1] > right:
                    self.ranges[i][0] = right
                else:
                    self.ranges.pop(i)
                    i -= 1
        while i + 1 < len(self.ranges) and self.ranges[i][1] == self.ranges[i + 1][0]:
            self.ranges[i][1] = self.ranges[i + 1][1]
            self.ranges.pop(i + 1)
